                RubikDataPathSequenceMerge();
                break;
#pragma CTC SKIP
            default: 
                FAIL(("NV_NVDLA_rbk::RubikDataPathSequenceThread, unexpected RUBIK_MODE setting"));
                break;
#pragma CTC ENDSKIP
        }
    }
}

